{
    /** @var AdminMiddleware $admin */
    $admin = $this->container->get(AdminMiddleware::class);
    $app = new AdminAppController($this->publicRoot);
    $redirect = $app->gateRedirect($admin->checkAccess($request));
    return $redirect ?? $app->shell($request, []);
}

