/**
 * Empty string posterUrl on a child item must not produce a child poster
 * load command — it is skipped silently just like a null URL. The sibling
 * child with a real (local-server) poster loads, so exactly ONE child poster
 * resolves.
 */
public function testEmptyStringPosterUrlForChildIsSkippedAndDoesNotCrash(): void
{
    $port = $this->startPosterServer();
    $base = "http://127.0.0.1:{$port}";
    [, $posterCmd] = $this->loadedContainerWithPosterCmd([
        ['id' => 's1', 'name' => 'Season 1', 'type' => 'season', 'poster_url' => ''],
        ['id' => 's2', 'name' => 'Season 2', 'type' => 'season', 'poster_url' => "{$base}/poster.png"],
    ], $base);

    $posterMsgs = array_filter($this->runBatch($posterCmd), static fn (Msg $m): bool => $m instanceof ChildPosterLoadedMsg);
    self::assertCount(1, $posterMsgs, 'only the valid child poster loads, the empty string is skipped');
}

/**
 * A relative URL (no scheme, e.g. /poster.png) on a child item IS resolved to
 * an absolute URL (baseUrl + path) and loaded — it is NOT skipped. Here the
 * base IS the local poster server, so both the resolved relative URL and the
 * absolute sibling genuinely load, proving resolution happened before the
 * scheme check.
 */
public function testRelativeUrlPosterForChildIsResolvedAndLoaded(): void
{
    $port = $this->startPosterServer();
    $base = "http://127.0.0.1:{$port}";
    [, $posterCmd] = $this->loadedContainerWithPosterCmd([
